import{_ as d,o as e,c as r,a2 as o}from"./chunks/framework.DvFsUg-r.js";const b=JSON.parse('{"title":"CLI 명령 전체 레퍼런스","description":"","frontmatter":{},"headers":[],"relativePath":"hermes/reference/cli.md","filePath":"hermes/reference/cli.md","lastUpdated":1781092690000}'),a={name:"hermes/reference/cli.md"};function c(h,t,l,s,i,n){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="cli-명령-전체-레퍼런스" tabindex="-1">CLI 명령 전체 레퍼런스 <a class="header-anchor" href="#cli-명령-전체-레퍼런스" aria-label="Permalink to &quot;CLI 명령 전체 레퍼런스&quot;">​</a></h1><div class="badge-box"><span class="badge-red">Verified</span><span class="badge-teal">v0.8.0</span><span class="badge-gold">All Commands</span></div><blockquote><p>공식 CLI 레퍼런스 문서에서 직접 확인된 <strong>모든 <code>hermes &lt;sub&gt;</code> 명령, 플래그, 슬래시 명령</strong>을 한 곳에 정리합니다. 기본값과 짧은 플래그 이름까지 포함합니다.</p></blockquote><h2 id="글로벌-플래그" tabindex="-1">글로벌 플래그 <a class="header-anchor" href="#글로벌-플래그" aria-label="Permalink to &quot;글로벌 플래그&quot;">​</a></h2><p>모든 <code>hermes</code> 호출에 공통으로 적용되는 플래그.</p><table tabindex="0"><thead><tr><th>플래그</th><th>용도</th></tr></thead><tbody><tr><td><code>--version</code>, <code>-V</code></td><td>버전 출력</td></tr><tr><td><code>--profile &lt;name&gt;</code>, <code>-p &lt;name&gt;</code></td><td><a href="/hermes/features/profiles">프로파일</a> 선택</td></tr><tr><td><code>--resume</code>, <code>-r</code></td><td>마지막 세션 재개</td></tr><tr><td><code>--continue</code>, <code>-c</code></td><td>이전 대화 이어가기</td></tr><tr><td><code>--worktree</code>, <code>-w</code></td><td>Git worktree 격리 모드</td></tr><tr><td><code>--yolo</code></td><td>승인 없이 실행 (위험)</td></tr><tr><td><code>--pass-session-id</code></td><td>세션 ID를 호출 경로로 전파</td></tr></tbody></table><h2 id="서브커맨드-전체-목록" tabindex="-1">서브커맨드 전체 목록 <a class="header-anchor" href="#서브커맨드-전체-목록" aria-label="Permalink to &quot;서브커맨드 전체 목록&quot;">​</a></h2><h3 id="대화-기본-사용" tabindex="-1">대화 &amp; 기본 사용 <a class="header-anchor" href="#대화-기본-사용" aria-label="Permalink to &quot;대화 &amp; 기본 사용&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes chat</code></td><td>대화 시작 (기본 동작 — 인자 없이 실행 시 자동)</td></tr><tr><td><code>hermes setup</code></td><td>초기 설정 마법사</td></tr><tr><td><code>hermes status</code></td><td>전체 상태 요약 (모델·도구·API 키 건강도)</td></tr><tr><td><code>hermes doctor</code></td><td>환경 진단 — 문제 원인 추적</td></tr><tr><td><code>hermes version</code></td><td>버전 정보</td></tr><tr><td><code>hermes update</code></td><td>최신 버전 업데이트</td></tr><tr><td><code>hermes uninstall</code></td><td>제거</td></tr></tbody></table><h3 id="hermes-chat-플래그" tabindex="-1"><code>hermes chat</code> 플래그 <a class="header-anchor" href="#hermes-chat-플래그" aria-label="Permalink to &quot;`hermes chat` 플래그&quot;">​</a></h3><table tabindex="0"><thead><tr><th>플래그</th><th>용도</th></tr></thead><tbody><tr><td><code>-q, --query &lt;text&gt;</code></td><td>일회성 쿼리 (비대화형)</td></tr><tr><td><code>-m, --model &lt;name&gt;</code></td><td>이 턴만 다른 모델로</td></tr><tr><td><code>-t, --toolsets &lt;names&gt;</code></td><td>활성 도구셋 지정</td></tr><tr><td><code>--provider &lt;name&gt;</code></td><td>프로바이더 강제</td></tr><tr><td><code>-s, --skills &lt;names&gt;</code></td><td>활성화할 스킬</td></tr><tr><td><code>-v, --verbose</code></td><td>상세 출력</td></tr><tr><td><code>-Q, --quiet</code></td><td>조용한 모드</td></tr><tr><td><code>--worktree</code></td><td>Git worktree 격리</td></tr><tr><td><code>--checkpoints</code></td><td>파일 시스템 체크포인트 활성화</td></tr><tr><td><code>--yolo</code></td><td>승인 건너뛰기</td></tr><tr><td><code>--pass-session-id</code></td><td>세션 ID 전파</td></tr><tr><td><code>--source &lt;type&gt;</code></td><td>입력 소스 지정</td></tr><tr><td><code>--max-turns &lt;n&gt;</code></td><td>턴 상한 (기본 90)</td></tr></tbody></table><h3 id="모델-프로바이더" tabindex="-1">모델 &amp; 프로바이더 <a class="header-anchor" href="#모델-프로바이더" aria-label="Permalink to &quot;모델 &amp; 프로바이더&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes model</code></td><td>대화형 모델 선택기</td></tr><tr><td><code>hermes auth</code></td><td>프로바이더 인증 관리</td></tr><tr><td><code>hermes dump</code></td><td>현재 상태·설정 덤프 (디버깅용)</td></tr><tr><td><code>hermes logs</code></td><td>중앙 로그 뷰어 (v0.8.0+)</td></tr></tbody></table><h3 id="구성-관리" tabindex="-1">구성 관리 <a class="header-anchor" href="#구성-관리" aria-label="Permalink to &quot;구성 관리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes config</code></td><td>설정 보기</td></tr><tr><td><code>hermes config set &lt;key&gt; &lt;value&gt;</code></td><td>개별 키 변경</td></tr><tr><td><code>hermes tools</code></td><td>활성 도구 관리</td></tr><tr><td><code>hermes plugins</code></td><td>플러그인 관리</td></tr><tr><td><code>hermes mcp</code></td><td>MCP 서버 관리</td></tr><tr><td><code>hermes acp</code></td><td>ACP (IDE) 모드</td></tr></tbody></table><h3 id="세션-메모리" tabindex="-1">세션 &amp; 메모리 <a class="header-anchor" href="#세션-메모리" aria-label="Permalink to &quot;세션 &amp; 메모리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes sessions list</code></td><td>세션 목록</td></tr><tr><td><code>hermes sessions rename &lt;id&gt; &lt;name&gt;</code></td><td>이름 변경</td></tr><tr><td><code>hermes memory</code></td><td>메모리 관리 (편집·검색·리셋)</td></tr><tr><td><code>hermes honcho</code></td><td>Honcho 사용자 모델링 관리</td></tr><tr><td><code>hermes insights</code></td><td>사용량·스킬 통계 리포트</td></tr></tbody></table><h3 id="스킬-하위-명령-풍부" tabindex="-1">스킬 (하위 명령 풍부) <a class="header-anchor" href="#스킬-하위-명령-풍부" aria-label="Permalink to &quot;스킬 (하위 명령 풍부)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes skills browse</code></td><td>카탈로그 탐색</td></tr><tr><td><code>hermes skills search &lt;q&gt;</code></td><td>키워드 검색</td></tr><tr><td><code>hermes skills install &lt;name&gt;</code></td><td>설치</td></tr><tr><td><code>hermes skills inspect &lt;name&gt;</code></td><td>스킬 상세</td></tr><tr><td><code>hermes skills list</code></td><td>설치된 스킬 목록</td></tr><tr><td><code>hermes skills check</code></td><td>무결성·의존성 검사</td></tr><tr><td>`hermes skills update [name</td><td>--all]`</td></tr><tr><td><code>hermes skills audit</code></td><td>보안·품질 감사</td></tr><tr><td><code>hermes skills uninstall &lt;name&gt;</code></td><td>제거</td></tr><tr><td><code>hermes skills publish &lt;name&gt;</code></td><td>허브 업로드</td></tr><tr><td><code>hermes skills snapshot &lt;name&gt;</code></td><td>스냅샷 저장</td></tr><tr><td><code>hermes skills tap</code></td><td>외부 스킬 소스 추가</td></tr><tr><td><code>hermes skills config &lt;name&gt;</code></td><td>스킬별 설정</td></tr></tbody></table><h3 id="게이트웨이-메시징" tabindex="-1">게이트웨이 &amp; 메시징 <a class="header-anchor" href="#게이트웨이-메시징" aria-label="Permalink to &quot;게이트웨이 &amp; 메시징&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes gateway</code></td><td>대화형 게이트웨이 설정</td></tr><tr><td><code>hermes gateway &lt;platform&gt;</code></td><td>특정 플랫폼 게이트웨이 시작</td></tr><tr><td><code>hermes gateway --all</code></td><td>활성 플랫폼 전부</td></tr><tr><td><code>hermes whatsapp</code></td><td>WhatsApp 전용 설정</td></tr><tr><td><code>hermes pairing</code></td><td>DM 페어링 관리</td></tr><tr><td><code>hermes webhook</code></td><td>웹훅 구성</td></tr></tbody></table><h3 id="자동화" tabindex="-1">자동화 <a class="header-anchor" href="#자동화" aria-label="Permalink to &quot;자동화&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes cron</code></td><td>크론 작업 관리</td></tr></tbody></table><h3 id="프로파일" tabindex="-1">프로파일 <a class="header-anchor" href="#프로파일" aria-label="Permalink to &quot;프로파일&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes profile list</code></td><td>프로파일 목록</td></tr><tr><td><code>hermes profile use &lt;name&gt;</code></td><td>전환</td></tr><tr><td><code>hermes profile create &lt;name&gt;</code></td><td>생성</td></tr><tr><td><code>hermes profile delete &lt;name&gt;</code></td><td>삭제</td></tr><tr><td><code>hermes profile show &lt;name&gt;</code></td><td>상세</td></tr><tr><td><code>hermes profile alias &lt;name&gt; &lt;alias&gt;</code></td><td>별칭</td></tr><tr><td><code>hermes profile rename &lt;old&gt; &lt;new&gt;</code></td><td>이름 변경</td></tr><tr><td><code>hermes profile export &lt;name&gt;</code></td><td>내보내기</td></tr><tr><td><code>hermes profile import &lt;path&gt;</code></td><td>가져오기</td></tr></tbody></table><h3 id="마이그레이션-유틸리티" tabindex="-1">마이그레이션 &amp; 유틸리티 <a class="header-anchor" href="#마이그레이션-유틸리티" aria-label="Permalink to &quot;마이그레이션 &amp; 유틸리티&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>hermes claw migrate</code></td><td>OpenClaw에서 자동 이전</td></tr><tr><td><code>hermes claw migrate --dry-run</code></td><td>미리보기</td></tr><tr><td><code>hermes claw migrate --preset &lt;name&gt;</code></td><td>프리셋 선택 (user-data 등)</td></tr><tr><td><code>hermes claw migrate --overwrite</code></td><td>충돌 시 덮어쓰기</td></tr><tr><td><code>hermes completion</code></td><td>셸 자동완성 스크립트 생성</td></tr></tbody></table><h2 id="슬래시-명령" tabindex="-1">슬래시 명령 <a class="header-anchor" href="#슬래시-명령" aria-label="Permalink to &quot;슬래시 명령&quot;">​</a></h2><p>대화 중 입력하는 <code>/</code> 명령.</p><h3 id="세션-제어" tabindex="-1">세션 제어 <a class="header-anchor" href="#세션-제어" aria-label="Permalink to &quot;세션 제어&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>/new</code>, <code>/reset</code></td><td>새 세션</td></tr><tr><td><code>/retry</code></td><td>마지막 응답 재생성</td></tr><tr><td><code>/undo</code></td><td>마지막 턴 되돌리기</td></tr><tr><td><code>/title &lt;text&gt;</code></td><td>세션 이름 설정</td></tr><tr><td><code>/stop</code></td><td>현재 작업 중단</td></tr><tr><td><code>/compress</code></td><td>컨텍스트 압축</td></tr><tr><td><code>/save</code></td><td>명시적 저장</td></tr></tbody></table><h3 id="모델-구성" tabindex="-1">모델 &amp; 구성 <a class="header-anchor" href="#모델-구성" aria-label="Permalink to &quot;모델 &amp; 구성&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>/model</code></td><td>모델 선택기</td></tr><tr><td><code>/model &lt;name&gt;</code></td><td>지정 모델로 전환</td></tr><tr><td><code>/model &lt;provider&gt;:&lt;model&gt;</code></td><td>프로바이더+모델</td></tr><tr><td><code>/personality [name]</code></td><td>페르소나 전환</td></tr><tr><td><code>/reasoning [high|medium|low]</code></td><td>추론 깊이</td></tr><tr><td><code>/tools</code></td><td>도구 토글</td></tr><tr><td><code>/verbose</code></td><td>상세 모드 토글</td></tr><tr><td><code>/skin [name]</code></td><td>TUI 스킨 변경</td></tr><tr><td><code>/voice on</code>, <code>/voice tts</code></td><td>음성 모드</td></tr><tr><td><code>/yolo</code></td><td>승인 게이트 해제</td></tr></tbody></table><h3 id="스킬-서브에이전트" tabindex="-1">스킬 &amp; 서브에이전트 <a class="header-anchor" href="#스킬-서브에이전트" aria-label="Permalink to &quot;스킬 &amp; 서브에이전트&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>/skills</code></td><td>활성 스킬 목록</td></tr><tr><td><code>/skills browse</code></td><td>허브 탐색</td></tr><tr><td><code>/&lt;skill-name&gt;</code></td><td>직접 실행 (예: <code>/gif-search</code>, <code>/github-pr-workflow</code>)</td></tr><tr><td><code>/background &lt;prompt&gt;</code>, <code>/bg</code></td><td>서브에이전트 백그라운드 스폰</td></tr></tbody></table><h3 id="상태-분석" tabindex="-1">상태 &amp; 분석 <a class="header-anchor" href="#상태-분석" aria-label="Permalink to &quot;상태 &amp; 분석&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>/usage</code></td><td>토큰·비용·캐시 적중률</td></tr><tr><td><code>/insights [--days N]</code></td><td>N일 사용 분석</td></tr><tr><td><code>/status</code></td><td>메시징 환경 상태</td></tr><tr><td><code>/platforms</code></td><td>활성 플랫폼 (CLI 버전)</td></tr><tr><td><code>/help</code></td><td>도움말</td></tr></tbody></table><h3 id="메시징-특화" tabindex="-1">메시징 특화 <a class="header-anchor" href="#메시징-특화" aria-label="Permalink to &quot;메시징 특화&quot;">​</a></h3><table tabindex="0"><thead><tr><th>명령</th><th>설명</th></tr></thead><tbody><tr><td><code>/btw</code></td><td>메시징 환경용 보조</td></tr><tr><td><code>/branch</code></td><td>대화 분기</td></tr></tbody></table><h2 id="주요-환경-변수" tabindex="-1">주요 환경 변수 <a class="header-anchor" href="#주요-환경-변수" aria-label="Permalink to &quot;주요 환경 변수&quot;">​</a></h2><p><code>hermes</code> 호출 전 설정하는 환경 변수 중 자주 쓰는 것들. 전체는 <a href="/hermes/reference/config">설정 레퍼런스</a>에서.</p><table tabindex="0"><thead><tr><th>변수</th><th>용도</th></tr></thead><tbody><tr><td><code>HERMES_YOLO_MODE</code></td><td>전역 YOLO 모드</td></tr><tr><td><code>HERMES_STREAM_READ_TIMEOUT</code></td><td>스트림 읽기 타임아웃 (기본 120초)</td></tr><tr><td><code>HERMES_STREAM_STALE_TIMEOUT</code></td><td>스트림 정체 감지 (기본 180초)</td></tr><tr><td><code>HERMES_API_TIMEOUT</code></td><td>API 타임아웃 (기본 1800초)</td></tr><tr><td><code>TERMINAL_SSH_HOST/USER/PORT/KEY</code></td><td>SSH 백엔드</td></tr><tr><td><code>TERMINAL_LOCAL_PERSISTENT</code></td><td>로컬 셸 영구 모드</td></tr><tr><td><code>MESSAGING_CWD</code></td><td>메시징 환경 작업 디렉토리</td></tr></tbody></table><h2 id="종료-코드" tabindex="-1">종료 코드 <a class="header-anchor" href="#종료-코드" aria-label="Permalink to &quot;종료 코드&quot;">​</a></h2><table tabindex="0"><thead><tr><th>코드</th><th>의미</th></tr></thead><tbody><tr><td>0</td><td>정상 종료</td></tr><tr><td>1</td><td>일반 에러</td></tr><tr><td>2</td><td>설정 오류</td></tr><tr><td>130</td><td>Ctrl+C 인터럽트</td></tr></tbody></table><hr><div class="tip custom-block"><p class="custom-block-title">다음 단계</p><ul><li>설정 키를 찾는다면 → <a href="/hermes/reference/config">설정 및 환경 변수 레퍼런스</a></li><li>내부 동작 원리 → <a href="/hermes/reference/internals">아키텍처 내부 동작</a></li></ul></div>',46)])])}const p=d(a,[["render",c]]);export{b as __pageData,p as default};
